module shift_register_16bit(D, CLK, LOAD, Q);
input [15:0] D;
input CLK, LOAD;
output reg Q;

reg [15:0] unused_register;

always @(posedge CLK) begin
    if (LOAD)
        unused_register <= D;
    else
        unused_register <= {1'b0, unused_register[15:1]};
    Q <= unused_register[0];
end

endmodule
